// Object literal — a single person
let person = {
  name: 'Alice',
  age: 30,
  greet: function () {
    return 'Hi, I am ' + this.name;
  }
};
console.log(person.greet());
// Expected output: Hi, I am Alice

// Class — blueprint for many objects
class Student {
  constructor(name, grade) {
    this.name = name;
    this.grade = grade;
  }
  describe() {
    return this.name + ' has grade ' + this.grade;
  }
}
let s = new Student('Bob', 'A');
console.log(s.describe());
// Expected output: Bob has grade A
